#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int main(int argc, char *argv[]) {
    if(argc < 2) {
        printf("You forgot to type the filename\n");
        return 1;
    }

    char filepath[100] = "/etc/myapp/configs/";
    strcat(filepath, argv[1]);

    FILE *file = fopen(filepath, "r");
    if (file == NULL){
        printf("Could not open file %s", filepath);
        return 1;
    }

    char ch;
    while((ch = fgetc(file)) != EOF)
        printf("%c", ch);

    fclose(file);

    return 0;
}